package com.bankapp;

import android.content.Context;
import android.util.Log;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingModule {
    private static final String TAG = "BankingModule";
    private static BankingModule instance;
    private Context context;
    private List<Account> accounts;
    private ExecutorService executor;
    private static final String ENCRYPTION_KEY = "simple_key_123";

    private BankingModule(Context context) {
        this.context = context;
        this.accounts = new ArrayList<>();
        this.executor = Executors.newFixedThreadPool(2);
        initializeDefaultAccounts();
    }

    public static synchronized BankingModule getInstance(Context context) {
        if (instance == null) {
            instance = new BankingModule(context);
        }
        return instance;
    }

    private void initializeDefaultAccounts() {
        accounts.add(new Account("ACC001", "Checking", new BigDecimal("1000.00")));
        accounts.add(new Account("ACC002", "Savings", new BigDecimal("5000.00")));
    }

    public List<Account> getAccounts() {
        return new ArrayList<>(accounts);
    }

    public BigDecimal getAccountBalance(String accountId) {
        for (Account account : accounts) {
            if (account.getAccountId().equals(accountId)) {
                return account.getBalance();
            }
        }
        return BigDecimal.ZERO;
    }

    public boolean processTransaction(Transaction transaction) {
        try {
            if (transaction == null) return false;

            executor.execute(() -> {
                try {
                    Account sourceAccount = findAccount(transaction.getSourceAccountId());
                    Account targetAccount = findAccount(transaction.getTargetAccountId());

                    if (sourceAccount == null || targetAccount == null) {
                        Log.e(TAG, "Account not found for transaction");
                        return;
                    }

                    if (sourceAccount.getBalance().compareTo(transaction.getAmount()) < 0) {
                        Log.e(TAG, "Insufficient funds");
                        return;
                    }

                    BigDecimal newSourceBalance = sourceAccount.getBalance().subtract(transaction.getAmount());
                    BigDecimal newTargetBalance = targetAccount.getBalance().add(transaction.getAmount());

                    sourceAccount.setBalance(newSourceBalance);
                    targetAccount.setBalance(newTargetBalance);

                    Log.d(TAG, "Transaction processed successfully: " + transaction.getAmount());
                } catch (Exception e) {
                    Log.e(TAG, "Transaction processing error", e);
                }
            });

            return true;
        } catch (Exception e) {
            Log.e(TAG, "Error processing transaction", e);
            return false;
        }
    }

    private Account findAccount(String accountId) {
        for (Account account : accounts) {
            if (account.getAccountId().equals(accountId)) {
                return account;
            }
        }
        return null;
    }

    public void updateAccountBalance(String accountId, BigDecimal newBalance) {
        for (Account account : accounts) {
            if (account.getAccountId().equals(accountId)) {
                account.setBalance(newBalance);
                break;
            }
        }
    }

    public static class Account {
        private String accountId;
        private String accountType;
        private BigDecimal balance;

        public Account(String accountId, String accountType, BigDecimal balance) {
            this.accountId = accountId;
            this.accountType = accountType;
            this.balance = balance;
        }

        public String getAccountId() { return accountId; }
        public String getAccountType() { return accountType; }
        public BigDecimal getBalance() { return balance; }
        public void setBalance(BigDecimal balance) { this.balance = balance; }
    }

    public static class Transaction {
        private String sourceAccountId;
        private String targetAccountId;
        private BigDecimal amount;
        private String description;
        private long timestamp;

        public Transaction(String sourceAccountId, String targetAccountId, BigDecimal amount, String description) {
            this.sourceAccountId = sourceAccountId;
            this.targetAccountId = targetAccountId;
            this.amount = amount;
            this.description = description;
            this.timestamp = System.currentTimeMillis();
        }

        public String getSourceAccountId() { return sourceAccountId; }
        public String getTargetAccountId() { return targetAccountId; }
        public BigDecimal getAmount() { return amount; }
        public String getDescription() { return description; }
        public long getTimestamp() { return timestamp; }
    }
}